1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	  material?: string;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Damage {
14	  itemType: string;
15	  amount: number;
16	}
17	
18	interface Incident {
19	  cause: string;
20	  damages: Damage[];
21	}
22	
23	interface ClaimStep {
24	  op: "claim";
25	  policy: number;
26	  incident: Incident;
27	}
28	
29	type Step = QuoteStep | ClaimStep;
30	
31	interface Customer {
32	  yearsWithMHPCO: number;
33	}
34	
35	interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	interface QuoteResult {
41	  premium: number;
42	}
43	interface ClaimResult {
44	  payout: number;
45	  remainingCap: number;
46	}
47	type StepResult = QuoteResult | ClaimResult;
48	
49	const BASE_PREMIUMS: Record<string, number> = {
50	  sword: 100,
51	  amulet: 60,
52	  staff: 80,
53	  potion: 40,
54	  rune: 25,
55	  moonstone: 25,
56	};
57	
58	const PROCESSING_FEE_G = 5;
59	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1; // 10% surcharge on policy base
60	const COMPONENT_BLOCK_SIZE = 3;
61	const COMPONENT_BLOCK_PRICE_G = 60;
62	const CURSE_SURCHARGE_RATE = 0.5; // 50% of cursed item's base premium
63	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3; // 30% of enchanted item's base premium
64	const HIGH_ENCHANTMENT_THRESHOLD = 5;
65	
66	const COMPONENT_TYPES = ["rune", "moonstone"];
67	
68	const priceForComponentGroup = (count: number, unitPrice: number): number =>
69	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PRICE_G : count * unitPrice;
70	
71	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
72	
73	const isCursed = (item: Item): boolean => item.cursed === true;
74	const isHighlyEnchanted = (item: Item): boolean =>
75	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
76	
77	const surchargeFor = (items: Item[], predicate: (i: Item) => boolean, rate: number): number =>
78	  items.filter(predicate).reduce((sum, item) => sum + BASE_PREMIUMS[item.type] * rate, 0);
79	
80	const LOYALTY_YEARS_THRESHOLD = 2;
81	const LOYALTY_DISCOUNT_RATE = 0.2; // 20% discount on policy base
82	const FOLLOW_UP_CONTRACT_DISCOUNT_RATE = 0.15; // 15% discount on policy base for contracts after the first
83	
84	const isLoyalCustomer = (customer: Customer): boolean =>
85	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
86	
87	const componentsBase = (items: Item[]): number =>
88	  COMPONENT_TYPES.reduce((sum, type) => {
89	    const count = items.filter((i) => i.type === type).length;
90	    return sum + priceForComponentGroup(count, BASE_PREMIUMS[type]);
91	  }, 0);
92	
93	const nonComponentsBase = (items: Item[]): number =>
94	  items.filter((i) => !isComponent(i)).reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
95	
96	const policyBaseFor = (items: Item[]): number =>
97	  componentsBase(items) + nonComponentsBase(items);
98	
99	const discountIf = (applies: boolean, base: number, rate: number): number =>
100	  applies ? base * rate : 0;
101	
102	const quotePremium = (items: Item[], customer: Customer, isFollowUpContract: boolean): number => {
103	  const policyBase = policyBaseFor(items);
104	  const curseSurcharge = surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
105	  const enchantmentSurcharge = surchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE_RATE);
106	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
107	  const loyaltyDiscount = discountIf(isLoyalCustomer(customer), policyBase, LOYALTY_DISCOUNT_RATE);
108	  const followUpDiscount = discountIf(isFollowUpContract, policyBase, FOLLOW_UP_CONTRACT_DISCOUNT_RATE);
109	  return Math.ceil(
110	    policyBase +
111	      curseSurcharge +
112	      enchantmentSurcharge +
113	      firstInsuranceSurcharge -
114	      loyaltyDiscount -
115	      followUpDiscount +
116	      PROCESSING_FEE_G,
117	  );
118	};
119	
120	const INSURANCE_VALUES: Record<string, number> = {
121	  sword: 1000,
122	  amulet: 600,
123	  staff: 800,
124	  potion: 400,
125	  rune: 250,
126	  moonstone: 250,
127	};
128	const DEDUCTIBLE_G = 100;
129	const CAP_MULTIPLIER = 2;
130	
131	interface PolicyState {
132	  items: Item[];
133	  remainingCap: number;
134	}
135	
136	const insuranceSumFor = (items: Item[]): number =>
137	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
138	
139	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
140	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
141	
142	const reimbursableAmountFor = (damage: Damage, item: Item): number =>
143	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD
144	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
145	    : damage.amount;
146	
147	const payoutForDamage = (damage: Damage, item: Item): number =>
148	  reimbursableAmountFor(damage, item) - DEDUCTIBLE_G;
149	
150	const findInsuredItem = (items: Item[], itemType: string): Item | undefined =>
151	  items.find((i) => i.type === itemType);
152	
153	const openPolicy = (items: Item[]): PolicyState => ({
154	  items,
155	  remainingCap: CAP_MULTIPLIER * insuranceSumFor(items),
156	});
157	
158	const settleClaim = (policy: PolicyState, incident: Incident): ClaimResult => {
159	  const rawPayout = incident.damages.reduce((sum, d) => {
160	    const item = findInsuredItem(policy.items, d.itemType);
161	    return sum + (item ? payoutForDamage(d, item) : 0);
162	  }, 0);
163	  const payout = Math.min(rawPayout, policy.remainingCap);
164	  policy.remainingCap -= payout;
165	  return { payout, remainingCap: policy.remainingCap };
166	};
167	
168	export const processScenario = (scenario: Scenario): { results: StepResult[] } => {
169	  const policies: Record<number, PolicyState> = {};
170	  let quoteCount = 0;
171	
172	  const handleQuote = (step: QuoteStep, index: number): QuoteResult => {
173	    const premium = quotePremium(step.items, scenario.customer, quoteCount > 0);
174	    quoteCount += 1;
175	    policies[index] = openPolicy(step.items);
176	    return { premium };
177	  };
178	
179	  const handleStep = (step: Step, index: number): StepResult =>
180	    step.op === "quote" ? handleQuote(step, index) : settleClaim(policies[step.policy], step.incident);
181	
182	  return { results: scenario.steps.map(handleStep) };
183	};
